def _default_attrs_for_user(username: str) -> dict:
    attrs = {
        "email": username,
        "uid": username.split("@")[0] if "@" in username else username,
    }
    if DEFAULT_ATTRS_JSON:
        try:
            extra = json.loads(DEFAULT_ATTRS_JSON)
            if isinstance(extra, dict):
                attrs.update(extra)
        except Exception:
            pass
    return attrs

